mapper.select:
SELECT FROM category
name LIKE CONCAT('%', #{keyword}, '%') OR slug LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%')
ORDER BY sort_order ASC, id ASC LIMIT #{offset}, #{pageSize}

mapper.insert:
INSERT INTO category (
    name, slug, parent_id, sort_order, description, article_count, status
) VALUES (
    #{name}, #{slug}, #{parentId}, #{sortOrder}, #{description}, #{articleCount}, #{status}
)

mapper.update:
UPDATE category SET
    status = #{status}
WHERE id = #{id}
